void countingSort(int arr[], int n) {
	if (n == 0) return;
	int max = arr[0];
	int min = arr[0];
	for (int i = 1; i < n; i++) {
		if (arr[i] > max) max = arr[i];
		if (arr[i] < min) min = arr[i];
	}
	int range = max - min + 1;
	int *count = (int *)calloc(range, sizeof(int));
	int *output = (int *)malloc(n * sizeof(int));
	for (int i = 0; i < n; i++) {
		count[arr[i] - min]++;
	}
	for (int i = 1; i < range; i++) {
		count[i] += count[i - 1];
	}
	for (int i = n - 1; i >= 0; i--) {
		output[count[arr[i] - min] - 1] = arr[i];
		count[arr[i] - min]--;
	}
	for (int i = 0; i < n; i++) {
		arr[i] = output[i];
	}
	free(count);
	free(output);
}
